Example Problem:
## Convert the below to a nested dict comprehension

result = {}

for col, vals in data.items():
    inner = {}
    for i, val in enumerate(vals):
        inner[val] = i
    result[col] = inner

## Convert the below to a list comprehension with filter

result = []

for x in nums:
    if x % 2 == 0:
        result.append(x)

## Convert the below to a list comprehension with if-else

result = []

for x in nums:
    if x % 2 == 0:
        result.append('even')
    else:
        result.append('odd')

## Convert the below to a nested list comprehension

result = []

for row in matrix:
    for num in row:
        result.append(num)

## Convert the below to a nested list comprehension with filter

result = []

for row in matrix:
    for num in row:
        if num > 0:
            result.append(num)

## Convert the below to a nested list comprehension with if-else

result = []

for row in matrix:
    for num in row:
        if num > 0:
            result.append(num)
        else:
            result.append(0)

## Convert the below to a dict comprehension

result = {}

for name in names:
    result[name] = len(name)

## Convert the below to a dict comprehension with filter

result = {}

for item, count in inventory.items():
    if count > 0:
        result[item] = count

## Convert the below to a nested list comprehension creating tuples

result = []

for i, row in enumerate(matrix):
    for num in row:
        result.append((i, num))

## Convert the below to a nested list comprehension creating dictionaries

result = []

for col, inner in mapping.items():
    for val, enc in inner.items():
        result.append({'column': col, 'value': val, 'encoding': enc})
